def token_f1(a,b):
    ta = normalize_for_sim(a).split()
    tb = normalize_for_sim(b).split()
    common = sum(min(ta.count(tok), tb.count(tok)) for tok in set(ta))
    if not ta or not tb:
        return 0.0
    precision = common / len(tb)
    recall = common / len(ta)
    if precision+recall==0:
        return 0.0
    return 2*precision*recall/(precision+recall), precision, recall, common, len(tb), len(ta)

